const item = $input.first();
const src = item.json || {};
const raw = [src.chatInput, src.text, src.message, src.prompt, src.input].find((v) => typeof v === 'string' && v.trim()) || JSON.stringify(src);
const now = new Date().toISOString();
const requestId = `council-${now.replace(/[:.]/g, '-')}`;

const councilRequest = {
  schema_version: '1.0',
  request_id: requestId,
  decision_type: 'business_decision',
  question: raw.trim(),
  context: '',
  options_considered: [],
  preferred_option: null,
  time_horizon: null,
  capital_at_risk: null,
  resource_commitment: null,
  upside_case: null,
  base_case: null,
  downside_case: null,
  known_risks: [],
  unknowns: [],
  constraints: [],
  values_or_principles: [],
  requested_at: now
};

return [{
  json: {
    requestId,
    rawUserMessage: raw.trim(),
    councilRequest,
    orchestratorPrompt: JSON.stringify(councilRequest, null, 2)
  }
}];

const src = $('Prepare Council Input').first().json;
let raw = $input.first().json.output ?? $input.first().json.response ?? $input.first().json.text ?? $input.first().json.result ?? '';
if (typeof raw !== 'string') raw = JSON.stringify(raw ?? {});
raw = raw.trim();
if (raw.startsWith('```')) {
  const lines = raw.split('\n');
  if (lines[0].startsWith('```')) lines.shift();
  if (lines.length && lines[lines.length - 1].startsWith('```')) lines.pop();
  raw = lines.join('\n').trim();
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    schema_version: '1.0',
    request_id: src.requestId,
    status: 'failed',
    decision_summary: 'Council output parse failure',
    final_recommendation: 'Retry after checking the council workflow output format.',
    agent_views: [],
    cross_agent_agreements: [],
    cross_agent_disagreements: [`Council output was not valid JSON: ${error.message}`],
    highest_priority_risks: ['Council output could not be parsed'],
    missing_information: [],
    next_steps: ['Retry the workflow', 'Inspect orchestrator output formatting'],
    overall_confidence: 0
  };
}

return [{ json: { ...src, councilResult: parsed } }];

const result = $input.first().json.councilResult || {};
const clean = (arr) => Array.isArray(arr) ? arr.filter(Boolean) : [];
const lines = [];

if (result.status === 'needs_clarification') {
  lines.push('Need more information before the council can review this.');
  lines.push('');
  const missing = clean(result.missing_information);
  if (missing.length) {
    lines.push('Missing information:');
    for (const row of missing) lines.push(`- ${row}`);
    lines.push('');
  }
  const next = clean(result.next_steps);
  if (next.length) {
    lines.push('Follow-up questions:');
    for (const row of next) lines.push(`- ${row}`);
  }
} else {
  lines.push(`Recommendation: ${result.final_recommendation || 'No recommendation generated.'}`);
  lines.push('');
  lines.push(`Why: ${result.decision_summary || 'No summary generated.'}`);
  lines.push('');
  const agree = clean(result.cross_agent_agreements);
  if (agree.length) {
    lines.push('Where the agents agree:');
    for (const row of agree) lines.push(`- ${row}`);
    lines.push('');
  }
  const disagree = clean(result.cross_agent_disagreements);
  if (disagree.length) {
    lines.push('Where the agents disagree:');
    for (const row of disagree) lines.push(`- ${row}`);
    lines.push('');
  }
  const risks = clean(result.highest_priority_risks);
  if (risks.length) {
    lines.push('Biggest risks:');
    for (const row of risks) lines.push(`- ${row}`);
    lines.push('');
  }
  const missing = clean(result.missing_information);
  if (missing.length) {
    lines.push('Missing information:');
    for (const row of missing) lines.push(`- ${row}`);
    lines.push('');
  }
  const next = clean(result.next_steps);
  if (next.length) {
    lines.push('Next steps:');
    for (const row of next) lines.push(`- ${row}`);
  }
}

return [{ json: { text: lines.join('\n').trim(), councilResult: result } }];
